module RefModule(
    input  D,
    output Q,
    input  SCD,
    input  SCE,
    input  CLK
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB;
    supply0 VNB;

    // Flip-flop for storing input value
    reg unused_stored_D;
    always @(posedge CLK) begin
        if (SCE) unused_stored_D <= SCD;
        else unused_stored_D <= D;
    end

    // Combinational logic for generating output
    assign Q = unused_stored_D;

endmodule
